member.example:
Bind the TMP_InputField text in TwoWay mode using a serialized binder field — the target is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private InputFieldBinder _username;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public string _username;
    }


Bind the TMP_InputField text in TwoWay mode by constructing the binder in code — changes in the input field are forwarded through the ValueChanged event.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private TMP_InputField _inputField;
        
        private InputFieldBinder Username =>
            new(_inputField);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public string _username;
    }
